VALUES
  ('cpa-moex-00351', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司的董事甲違反證券交易法有關內線交易之規定，則甲依法對於當日善意從事相反買賣 之人買入或賣出該證券之價格，與消息公開後幾個營業日收盤平均價格之差額，負損害賠償責任； 其情節重大者，法院得依善意從事相反買賣之人之請求，將賠償額提高至幾倍？', '["三個營業日；二倍", "五個營業日；二倍", "七個營業日；三倍", "十個營業日；三倍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00352', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '自然人甲於證券集中市場購得股票上市之A股份有限公司已發行股份總計剛好為百分之十，依證 券交易法規定，甲對於上述購得股份之行為應如何處置？', '["甲應申報且公告", "甲只須申報，不必公告", "甲不必申報，必須公告", "甲不必申報亦不必公告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00353', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何人不得充任證券商之董事、監察人或經理人；其已充任者，解任之？', '["甲曾任A法人宣告破產時之經理人，其破產終結已逾三年", "B證券商之經理人乙，在未有投資關係，亦未經主管機關核准之情形，兼任C證券商之研究員", "丙五年前在金融機構有拒絕往來之紀錄", "丁曾犯詐欺罪經宣告有期徒刑六個月確定，尚未執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00354', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列涉及現金之交易，何者不符合商業會計法第9條之規定？', '["甲公司以活期存款取款條自銀行提取新臺幣105萬元現金支付上游廠商貨款", "乙公司以活期存款取款條轉帳新臺幣200萬元給債權人償還部分借款", "丙公司出售汽車而自某君收到新臺幣110萬元現金", "丁公司購買機器設備電匯新臺幣150萬元給賣方"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00355', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依據商業會計法有關會計憑證的規定，下列敘述何者錯誤？', '["商業會計憑證分為原始憑證與記帳憑證", "原始憑證是專指因為發生商業活動由商業本身給予外人的證明", "商業會計之處理，記帳憑證為記帳所根據之憑證", "商業會計事務較簡單者得不編製記帳憑證"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00356', 'cpa', 'cpa-moex-111-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依商業會計處理準則規定，下列那一種資產，於資產減損後，當有證據顯示以前期間所認列之減 損損失，可能已不存在或減少時，資產帳面金額仍不予迴轉？', '["採權益法之投資", "以成本衡量之權益工具投資", "以攤銷後成本衡量之債務工具投資", "無活絡市場之債務工具投資"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:03+00:00", "source_pdf_sha1": "7c6dca5a9919", "answer_pdf_sha1": "113e6e415060", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00357', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'essay', '依照審計準則 540 號（原審計準則公報第五十六號）「會計估計與相關揭
露之查核」規定，試回答下列小題：
查核人員於評估管理階層所採用假設之合理性時，試例舉二項宜考量
之事項。（4分）
管理階層所採用假設之合理性可能取決於其執行特定作為之意圖和
能力。查核人員對所取得與管理階層之意圖及能力有關之查核證據是
否足夠及適切，係屬專業判斷，試例舉三項查核程序。（6分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00358', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'essay', '依「審計準則委員會所發布規範會計師服務案件準則總綱」，會計師執行
確信案件的目的，在於取得足夠及適切之證據以作成結論，用以提升預
期使用者對依基準衡量或評估標的之結果的信賴水準。試問：
確信案件包含那些要素？（5分）
何謂合理確信案件？何謂有限確信案件？二者之區別為何？（5 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00359', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'essay', '請依審計準則315 號（原審計準則公報第七十五號）「辨認並評估重大
不實表達風險」回答下列問題：
何謂固有風險光譜？查核人員於決定所辨認風險處於固有風險光譜
之位置時，所考量的因素為何？（10分）
何謂顯著風險（significantrisk）？並請列出兩項審計準則明定為顯著
風險之重大不實表達風險。（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00360', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'essay', '民國 X8 年 12 月間，境外 W 市爆發民眾感染不明病毒引發之疫病，惟
截至當年度結束，僅有為數不多的類似個案通報國際衛生組織，當時尚
無人與人之間會相互傳染的明確證據。隨著疫情的發展與擴散，導致自
X9 年 1 月中開始的全境大規模封城與限制人員活動，嗣後逐漸擴散至
全球 180 餘國，國際衛生組織遂正式宣布此一疫病成為全球流行性疾病
（globalpandemic）。
甲公司係一知名國內上市公司，於 W市設有重要生產基地，產量占全公
司產能之75%，試問：
會計師受託查核甲公司 X8 年度財務報表，值此期末查核期間，如經專
業判斷認定此等疫情確實對甲公司之營運與財務造成衝擊，會計師應執
行何種查核程序以取得足夠且適切之查核證據？（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00361', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '關係人交易之性質可能導致較高之重大不實表達風險，下列敘述何者錯誤？', '["進行關係人交易之動機可能係為進行財務報導舞弊或掩飾被挪用之資產", "關係人交易通常透過複雜之關係及結構進行", "通常與關係人間之交易及餘額較容易從企業資訊系統中有效辨認或彙總", "關係人交易較易未依一般公平交易之條款及條件進行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00362', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關查核人員瞭解受查者及其環境，以辨認並評估重大不實表達風險之敘述，下列何者錯誤？', '["查核人員僅執行風險評估程序並無法提供足夠及適切之查核證據，以作為表示查核意見之基礎", "查核人員執行風險評估程序，其相關作業包括控制測試，以評估重大不實表達風險", "於查核財務報表時，查核人員一定要執行風險評估程序", "查核人員於評估重大不實表達風險階段，對內部控制作業執行簡易測試的目的並非在測試該控 制作業執行的有效性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00363', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列有關存貨查核之敍述，何者正確？', '["查核人員執行盤點測試，可提供存貨的存在與狀況之查核證據", "如由第三方保管之存貨對財務報表係屬重大，查核人員應向受查者管理階層取得書面聲明，以 確認該存貨之存在及狀況", "查核人員如因不可預見之班機取消致無法參與存貨盤點，則應逕行採用替代查核程序，以對存 貨的存在與狀況取得足夠且適切之查核證據", "受查者通常至少每年執行一次存貨盤點，以作為編製財務報表之基礎並用以確認其定期盤存制 之可靠性。惟受查者如採用永續盤存制時，查核人員僅針對受查者帳載進、銷貨資料進行查對 即可，無須參與實體盤點存貨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00364', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列何者非屬查核人員無法取得足夠及適切查核證據而出具保留意見之情形？', '["受查者會計紀錄已毀損，對財務報表之影響重大但非廣泛", "會計師接受委任之時點較晚，致無法觀察實體存貨盤點", "管理階層禁止查核人員對特定科目餘額發函詢證", "受查者財務報表未包括適用之財務報導架構規定之所有揭露"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00365', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關會計師查核一般用途財務報表之責任，下列敘述何者錯誤？', '["會計師應依照一般公認審計準則查核，運用專業判斷並保持專業上之懷疑", "對與查核攸關之內部控制取得必要之瞭解，以設計當時情況下適當之查核程序，並對受查者內 部控制之有效性表示意見", "評估管理階層所採用會計政策之適當性，及其所作會計估計與相關揭露之合理性", "當財務報表係依照允當表達架構編製時，應評估財務報表（包括相關附註）是否允當表達"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00366', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '針對查核人員用以辨認可能產生重大不實表達風險之訴訟與索賠之查核程序，下列敘述何者錯誤？', '["查詢管理階層及受查者之其他人員，包括內部法務人員", "複核治理單位之會議紀錄及受查者與其外部法律顧問之往來文件", "要求管理階層提供截至財務報導期間結束日對已知實際訴訟與索賠已告知查核人員之書面聲明", "複核法律費用科目"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00367', 'cpa', 'cpa-moex-111-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列敘述何者不是品質管制準則1號（原審計準則公報第四十六號）「會計師事務所之品質管制」 規定的品質管制制度六項要素之一？', '["事務所領導階層對品質管制之責任", "職業道德規範", "案件之承接與續任", "法令之遵循"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "16c9f593d647", "answer_pdf_sha1": "a6333c6eea94", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
